command.operation:
{literal}{
{/literal}
  {assign var=has_prev value=false}

  {*
    name
  *}
  {if $params.name}
    {if $has_prev},{/if}
    "name": "{$params.name}"
    {assign var=has_prev value=true}
  {/if}

  {*
    description
  *}
  {if $params.description}
    {if $has_prev},{/if}
    "description": "{$params.description}"
    {assign var=has_prev value=true}
  {/if}

 {*
    included_predefined_categories
  *}
  {if $params.included_predefined_categories}
    {if $has_prev},{/if}
    "included_predefined_categories": [
      {foreach $params.included_predefined_categories as $item}
      "{$item.included_predefined_categories}"{if !$item@last},{/if}
      {/foreach}
    ]
    {assign var=has_prev value=true}
  {/if}

  {*
    included_url_lists
  *}
  {if $params.included_url_lists}
    {if $has_prev},{/if}
    "included_url_lists": [
      {foreach $params.included_url_lists as $item}
      "{$item.included_url_lists}"{if !$item@last},{/if}
      {/foreach}
    ]
    {assign var=has_prev value=true}
  {/if}

  {*
    excluded_url_lists
  *}
  {if $params.excluded_url_lists}
    {if $has_prev},{/if}
    "excluded_url_lists": [
      {foreach $params.excluded_url_lists as $item}
      "{$item.excluded_url_lists}"{if !$item@last},{/if}
      {/foreach}
    ]
    {assign var=has_prev value=true}
  {/if}

  {*
    included_destination_profiles
  *}
  {if $params.included_destination_profiles}
    {if $has_prev},{/if}
    "included_destination_profiles": [
      {foreach $params.included_destination_profiles as $item}
      "{$item.included_destination_profiles}"{if !$item@last},{/if}
      {/foreach}
    ]
    {assign var=has_prev value=true}
  {/if}

  {*
    excluded_destination_profiles
  *}
  {if $params.excluded_destination_profiles}
    {if $has_prev},{/if}
    "excluded_destination_profiles": [
      {foreach $params.excluded_destination_profiles as $item}
      "{$item.excluded_destination_profiles}"{if !$item@last},{/if}
      {/foreach}
    ]
    {assign var=has_prev value=true}
  {/if}

